/**
 * SEO component that queries for data with
 * Gatsby's useStaticQuery React hook
 *
 * See: https://www.gatsbyjs.com/docs/how-to/querying-data/use-static-query/
 */

import * as React from 'react';
import {useStaticQuery, graphql} from 'gatsby';

const Seo = ({description, title, children, keywords, name}) => {

  const {site, allStrapiKeyword} = useStaticQuery(
      graphql`
      query {
        site {
          siteMetadata {
            title
            description
            author
          }
        }
          allStrapiKeyword {
    nodes {
      keywords
     description
      name
    }
  }
      }
    `,
  );
  if (name) {
    const keywordList = allStrapiKeyword.nodes;
    console.log(keywordList);
    const values = keywordList.filter(value => value.name === name);
    if (values && values.length) {
      const item = values[0];
      if (item.keywords) {
        keywords = item.keywords;
      }
      if (item.description) {
        description = item.description;
      }

    }

  }

  const metaDescription = description || site.siteMetadata.description;
  const defaultTitle = site.siteMetadata?.title;
  let show = title;
  if (defaultTitle) {
    if (title) {
      show = `${title} | ${defaultTitle}`;
    } else {
      show = defaultTitle;
    }
  }
  return (
      <>
        <title>{show}</title>
        <meta name="description" content={metaDescription}/>
        {keywords && <meta name="keywords" content={keywords}/>}
        {children}
      </>
  );
};

export default Seo;
